import os
from cryptography.fernet import Fernet

def generate_key():
    return Fernet.generate_key()

def load_key(key_path):
    with open(key_path, 'rb') as file:
        return file.read()

def save_key(key, key_path):
    with open(key_path, 'wb') as file:
        file.write(key)

def encrypt_card_number(card_number, key):
    f = Fernet(key)
    encrypted_card_number = f.encrypt(card_number.encode())
    return encrypted_card_number

def decrypt_card_number(encrypted_card_number, key):
    f = Fernet(key)
    decrypted_card_number = f.decrypt(encrypted_card_number).decode()
    return decrypted_card_number

# Example usage
if __name__ == "__main__":
    key_path = 'encryption.key'
    
    # Generate and save a new encryption key if it doesn't exist
    if not os.path.exists(key_path):
        key = generate_key()
        save_key(key, key_path)
    else:
        key = load_key(key_path)

    card_number = "1234-5678-9012-3456"
    encrypted_card = encrypt_card_number(card_number, key)
    print(f"Encrypted Card Number: {encrypted_card}")

    decrypted_card = decrypt_card_number(encrypted_card, key)
    print(f"Decrypted Card Number: {decrypted_card}")